using HttpClient client = new HttpClient();
client.DefaultRequestHeaders.Add("Authorization", "Bearer YOUR_API_KEY");

var url = "https://api.socialsent.com/v1/sentiment?" +
    "ticker=AAPL&" +
    "start_date=2025-01-01&" +
    "end_date=2025-01-15&" +
    "interval=hourly";

var response = await client.GetAsync(url);
var json = await response.Content.ReadAsStringAsync();

var options = new JsonSerializerOptions { PropertyNameCaseInsensitive = true };
var results = JsonSerializer.Deserialize<SentimentResult[]>(json, options);

foreach (var record in results.Take(5))
{
    Console.WriteLine($"{record.Ticker}: {record.SentimentScore} ({record.TweetVolume} tweets)");
}
